module top_module(
    input CLK,
    input RST,
    input START,
    input [15:0] DURATION,
    output reg PULSE
);reg [15:0] ERR_count;

always @(posedge CLK) begin
    if (RST) begin
        ERR_count <= 0;
        PULSE <= 0;
    end
    else if (START) begin
        if (ERR_count < DURATION) begin
            ERR_count <= ERR_count + 1;
            PULSE <= 1;
        end
        else begin
            ERR_count <= 0;
            PULSE <= 0;
        end
    end
    else begin
        ERR_count <= 0;
        PULSE <= 0;
    end
end

endmodule
